import { HugeiconsIcon } from "@hugeicons/react";
import type { CertificationRequestLifecycleStatus } from "@procertus-ui/ui-certification";
import {
  Avatar,
  AvatarFallback,
  Badge,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Separator,
  cn,
  iconStroke,
} from "@procertus-ui/ui";
import { useMockPrototypeSession } from "@procertus-ui/ui-pt1-prototype";
import { Link } from "react-router-dom";

import {
  requestStatus,
  requestTitle,
  useAuthenticatedRequests,
} from "../features/requests/authenticatedRequestStore";
import { PROTOTYPE_NAV_GROUPS, PROTOTYPE_PRIMARY_NAV, PROTOTYPE_SECONDARY_NAV, type PrototypeNavItem } from "../navConfig";
import { mockCertificateTeaser, mockFinancialOverview } from "./dashboard-mock-data";

function navItemByKey(key: string): PrototypeNavItem | undefined {
  const primary = PROTOTYPE_PRIMARY_NAV.find((i) => i.key === key);
  if (primary) return primary;
  for (const group of PROTOTYPE_NAV_GROUPS) {
    const found = group.items.find((i) => i.key === key);
    if (found) return found;
  }
  return undefined;
}

function initialsFromDisplayName(name: string): string {
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "?";
  if (parts.length === 1) return parts[0]!.slice(0, 2).toUpperCase();
  return `${parts[0]![0]!}${parts[parts.length - 1]![0]!}`.toUpperCase();
}

const formatDate = (value?: string) =>
  value
    ? new Intl.DateTimeFormat("nl-BE", {
        day: "numeric",
        month: "short",
      }).format(new Date(value))
    : undefined;

function isActiveRequestStatus(status: CertificationRequestLifecycleStatus): boolean {
  return status === "draft" || status === "submitted" || status === "in-progress";
}

function statusBadgeVariant(
  status: CertificationRequestLifecycleStatus,
): "default" | "secondary" | "success" | "warning" | "info" | "destructive" | "outline" {
  if (status === "draft") return "outline";
  if (status === "submitted") return "secondary";
  if (status === "in-progress") return "info";
  if (status === "approved") return "success";
  if (status === "rejected" || status === "cancelled") return "destructive";
  return "secondary";
}

function DashboardNavCard({
